function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch(url)
      .then(res => res.json())
      .then(data => {
        setData(data);
        setLoading(false);
      })
      .catch(err => {
        setError(err);
        setLoading(false);
      });
  }, [url]);

  return { data, loading, error };
}

// Using custom hook
function MyComponent() {
  const { data, loading, error } = useFetch('/api/users');
  
  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error!</p>;
  
  return <div>{data.name}</div>;
}`})}),a.jsxs("div",{className:"bg-blue-900/20 border border-blue-700 p-6 rounded-lg",children:[a.jsx("h3",{className:"text-xl font-bold text-blue-400 mb-3",children:"✅ Common Custom Hooks"}),a.jsxs("ul",{className:"grid grid-cols-1 md:grid-cols-2 gap-3 text-gray-200 text-sm",children:[a.jsx("li",{children:"• useLocalStorage - Persist state"}),a.jsx("li",{children:"• useFetch - Data fetching"}),a.jsx("li",{children:"• useAuth - Authentication"}),a.jsx("li",{children:"• useForm - Form handling"}),a.jsx("li",{children:"• usePrevious - Track previous value"}),a.jsx("li",{children:"• useDebounce - Debounce values"})]})]})]})}function Dh(){const[e,t]=v.useState(!1);return a.jsxs("div",{className:"animate-slideInLeft",children:[a.jsxs("div",{className:"mb-8",children:[a.jsx("h1",{className:"text-4xl font-bold mb-4 bg-gradient-to-r from-green-400 to-emerald-400 bg-clip-text text-transparent",children:"🔀 React Fragment - Clean DOM"}),a.jsx("p",{className:"text-lg text-gray-300",children:"React Fragments let you group elements without adding extra nodes to the DOM."})]}),a.jsxs("div",{className:"grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8",children:[a.jsxs("div",{className:"bg-red-900/30 p-6 rounded-lg border border-red-600",children:[a.jsx("h2",{className:"text-2xl font-bold mb-4 text-red-400",children:"❌ Without Fragment"}),a.jsx("p",{className:"text-gray-300 mb-3",children:"Extra div in DOM:"}),a.jsx("div",{className:"bg-slate-900 p-3 rounded text-sm text-red-300 overflow-auto",children:a.jsx("code",{children:`<div>
